    // Create a 2D array to store the results of subproblems
    int[][] dp = new int[k + 1][n + 1]

    // Base cases
    for (int i = 1; i <= k; i++) {
        dp[i][0] = 0
        dp[i][1] = 1
    }
    for (int j = 1; j <= n; j++) {
        dp[1][j] = j
    }

